#include<bits/stdc++.h>
#define ri register int
using namespace std;
int m,n,xg=1000000,x,a[1000005];
bool flag[1000005];
int main(void){
	cin>>m>>n;
	for(ri i=ceil(sqrt(double(m)));i*i<=1000000;i++){
		for(ri j=1;j*i*i<=1000000;j++){
			flag[j*i*i]=1;
		}
	}	
	for(ri i=1000000;i>=1;i--){
		if(flag[i])xg=i;
		else a[i]=xg;
	}
	while(n--){
		cin>>x;
		if(a[x]==0)cout<<"lucky\n";
		else cout<<a[x]<<'\n';
	}
	return false;
}
